/// Fold fcmp with a select result that selects between X and -X based on
/// comparison with zero.
/// fcmp Pred (select (fcmp cc X, 0), X, (fneg X)), 0.0 -> fcmp Pred X, 0.0
/// fcmp Pred (select (fcmp cc X, 0), (fneg X), X), 0.0 -> fcmp Pred X, 0.0
static Instruction *foldFCmpSelectFNegToFcmpZero(FCmpInst &I) {
  // Only handle comparisons with 0.0.
  const APFloat *C;
  if (!match(I.getOperand(1), m_APFloat(C)) || !C->isZero())
    return nullptr;

  Value *SelectVal = I.getOperand(0);
  Value *CondVal = nullptr;
  Value *TrueVal = nullptr;
  Value *FalseVal = nullptr;

  // Match select with condition and both operands.
  if (!match(SelectVal,
             m_Select(m_Value(CondVal), m_Value(TrueVal), m_Value(FalseVal))))
    return nullptr;

  // Check if the condition is an fcmp comparing a value with zero.
  CmpInst::Predicate CondPred;
  Value *X = nullptr;
  if (!match(CondVal, m_FCmp(CondPred, m_Value(X), m_AnyZeroFP())))
    return nullptr;

  // Check if select chooses between X and fneg(X).
  // Pattern 1: (fcmp cc X, 0) ? X : (fneg X)
  // Pattern 2: (fcmp cc X, 0) ? (fneg X) : X
  Value *NegVal = nullptr;
  if (TrueVal == X) {
    if (!match(FalseVal, m_FNeg(m_Specific(X))))
      return nullptr;
  } else if (match(TrueVal, m_FNeg(m_Specific(X)))) {
    if (FalseVal != X)
      return nullptr;
  } else {
    return nullptr;
  }

  // The select computes |X| or -|X| based on the condition.
  // Comparing |X| or -|X| with 0 is equivalent to comparing X with 0,
  // because |X| == 0 iff X == 0, and similarly for -|X|.
  // This is valid for all predicates because:
  // - For equality/inequality: |X| == 0 iff X == 0, |X| != 0 iff X != 0
  // - For ordered comparisons: |X| > 0 iff X > 0 or X < 0 (i.e., X != 0)
  // - For NaN: if X is NaN, |X| is NaN, and both comparisons return false for ordered
  //   predicates and true for unordered predicates, so behavior is preserved.
  return new FCmpInst(I.getPredicate(), X, I.getOperand(1), "", &I);
}
